assertion_results.evidence:
Direct statement: "Use pytest.mark.parametrize for a table-driven test." and multiple examples decorated with @pytest.mark.parametrize, e.g.,

@pytest.mark.parametrize(
    "email",
    [
        "a@b.com",
        ...
    ],
)
def test_valid_emails(email):
    assert validate_email(email) is True

Option B explicitly shows a single table with input and expected outcome:

@pytest.mark.parametrize(
    "email, expected",
    [
        ("a@b.com", True),
        ("user.name+tag@sub.example.co.uk", True),
        ("plainaddress", False),
        ("user@", False),
    ],
    ids=["simple", "plus-subdomain", "no-at", "no-domain"]
)
def test_validate_email_table(email, expected):
    assert validate_email(email) is expected
